		/* wms-ctmaster-centercode-sql-oracle.xml - selectCenterCodeDt */
		SELECT
			  A.CTKEY
			, A.CTCDHDKEY
			, A.LAKEY
			, B.CTCDDTNM AS LANAME
			, A.CTCDDTKEY
			, A.CTCDDTNM
			, A.CTCDDTORD
			, A.CTCDDTVAL
			, A.CMT
			, A.DELYN
		FROM TWORK_MST_CTCD_DT A
		LEFT OUTER JOIN TWORK_MST_CTCD_DT B
			ON B.CTKEY = A.CTKEY AND B.CTCDHDKEY = 'LAKEY' AND B.CTCDDTKEY = A.LAKEY AND B.LAKEY = #{slakey}
 		WHERE A.CTKEY = #{ctkey}
		AND A.CTCDHDKEY = #{ctcdhdkey}
		AND A.CTCDDTKEY = #{ctcddtkey}
		AND A.LAKEY = #{lakey}

